124→  'projects': 'compte', 'api-keys': 'compte', 'api-developer': 'compte',
125→  'affiliation': 'compte', 'integrations': 'compte', 'invoices': 'compte',
126→};
127→
128→const App: React.FC = () => {
129→  return <AppContent />;
130→};
131→
132→const AppContent: React.FC = () => {
133→  // ── Toast system ──
134→  const [toasts, setToasts] = useState<Toast[]>([]);
135→  const showToast = useCallback((type: Toast['type'], message: string) => {
136→    const id = Date.now().toString();
137→    setToasts(prev => [...prev, { id, type, message }]);
138→    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 3500);
139→  }, []);
140→  const removeToast = useCallback((id: string) => {
141→    setToasts(prev => prev.filter(t => t.id !== id));
142→  }, []);
143→
144→  // ── Page transition ──
145→  const [pageKey, setPageKey] = useState(0);
146→
147→  // ── 2-level routing ──
148→  const [currentView, setCurrentView] = useState<string>('home');
149→  const [activeSection, setActiveSection] = useState<string>('dashboard');
150→  const [viewHistory, setViewHistory] = useState<string[]>([]);
151→  const [refreshKey, setRefreshKey] = useState(0);
152→
153→  const [analysisData, setAnalysisData] = useState<AnalysisResult | null>(null);
154→  const [history, setHistory] = useState<AnalysisResult[]>([]);
155→
156→  // Load history from DB on mount
157→  useEffect(() => {
158→    const loadedHistory = db.getAll();
159→    setHistory(loadedHistory);
160→  }, []);
161→
162→  // Bibliothèques de contenu généré
163→  const [smcLibrary, setSmcLibrary] = useState<SMCContent[]>([]);
164→  const [truthLibrary, setTruthLibrary] = useState<SMCContent[]>([]);
165→  const [schemaLibrary, setSchemaLibrary] = useState<SMCContent[]>([]);
166→  const [robotsLibrary, setRobotsLibrary] = useState<SMCContent[]>([]);
167→
168→  const [megaStatus, setMegaStatus] = useState<MegaGenerationStatus>('idle');
169→  const [isAnalyzing, setIsAnalyzing] = useState(false);
170→  const [resultsTab, setResultsTab] = useState<'overview' | 'details' | 'archives' | 'recommendations'>('overview');
171→  const [publisherRequestData, setPublisherRequestData] = useState<{ topic: string, url: string, brief: string } | null>(null);
172→  const [initialRechargePackId, setInitialRechargePackId] = useState<number | null>(null);
173→  const [initialAccountTab, setInitialAccountTab] = useState<'profile' | 'subscription' | 'billing'>('profile');
174→
175→  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
176→
177→  // Command Palette (Ctrl+K) & Keyboard Shortcuts (?)
178→  const [isCommandPaletteOpen, setIsCommandPaletteOpen] = useState(false);
179→  const [isShortcutsOpen, setIsShortcutsOpen] = useState(false);
180→  const [lowCreditsDismissed, setLowCreditsDismissed] = useState(false);
181→  useEffect(() => {
182→    const handleKeyDown = (e: KeyboardEvent) => {
183→      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
184→        e.preventDefault();
185→        setIsCommandPaletteOpen(prev => !prev);
186→      }
187→      if (e.key === 'Escape') {
188→        setIsCommandPaletteOpen(false);
189→        setIsShortcutsOpen(false);
190→      }
191→      if (e.key === '?' && !(e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement)) {
192→        setIsShortcutsOpen(prev => !prev);
193→      }
194→    };
195→    document.addEventListener('keydown', handleKeyDown);
196→    return () => document.removeEventListener('keydown', handleKeyDown);
197→  }, []);
198→
199→  // ── Welcome Onboarding Modal ──
200→  const [showOnboarding, setShowOnboarding] = useState(false);
201→
202→  // Default user is NULL to allow testing the login flow
203→  const [user, setUser] = useState<User | null>(null);
204→  const animatedCredits = useAnimatedNumber(user?.credits ?? 0);
205→  const [showCelebration, setShowCelebration] = useState(false);
206→
207→  // Show onboarding modal on first login
208→  useEffect(() => {
209→    if (user && !localStorage.getItem('citedby_onboarded')) {
210→      setShowOnboarding(true);
211→    }
212→  }, [user]);
213→
214→  // Calcul du nombre de projets consommé sur le mois en cours (Renouvellement mensuel)
215→  const monthlyProjectCount = useMemo(() => {
216→    if (history.length === 0) return 0;
217→
218→    const now = new Date();
219→    const billingCycleStart = new Date(now.getFullYear(), now.getMonth(), 1);
220→
221→    const projectCreationDates = new Map<string, Date>();
222→
223→    history.forEach(h => {
224→        let hostname;
225→        try { hostname = new URL(h.url).hostname; } catch(e) { hostname = h.url; }
226→
227→        const analysisDate = new Date(h.timestamp);
228→
229→        if (!projectCreationDates.has(hostname)) {
230→            projectCreationDates.set(hostname, analysisDate);
231→        } else {
232→            if (analysisDate < projectCreationDates.get(hostname)!) {
233→                projectCreationDates.set(hostname, analysisDate);
234→            }
235→        }
236→    });
237→
238→    let count = 0;
239→    projectCreationDates.forEach((creationDate) => {
240→        if (creationDate >= billingCycleStart) {
241→            count++;
242→        }
243→    });
244→
245→    return count;
246→  }, [history]);
247→
248→  // Vérifier si le plan d'action est complet
249→  const actionPlanStatus = useMemo(() => {
250→    if (history.length === 0) return { complete: false, completed: 0, total: 0 };
251→    const latest = history[history.length - 1];
252→    const total = latest.recommendations.length;
253→    const completed = latest.recommendations.filter(rec =>
254→      latest.generatedSolutions?.[rec.id]
255→    ).length;
256→    return { complete: total > 0 && completed === total, completed, total };
257→  }, [history]);
258→
259→  // ── Navigation ──
260→  const navigateTo = (view: string) => {
261→    setIsMobileMenuOpen(false);
262→    if (view !== 'recharge') setInitialRechargePackId(null);
263→    if (view !== 'account') setInitialAccountTab('profile');
264→    setViewHistory(prev => [...prev, currentView]);
265→    setCurrentView(view);
266→    // Auto-sync section from page
267→    const section = PAGE_TO_SECTION[view];
268→    if (section) setActiveSection(section);
269→    setRefreshKey(prev => prev + 1);
270→    setPageKey(prev => prev + 1);
271→  };
272→
273→  const handleSectionChange = (section: string) => {
274→    const firstPage = FIRST_PAGE_PER_SECTION[section] || section;
275→    navigateTo(firstPage);
276→  };
277→
278→  const handlePageChange = (page: string) => {
279→    navigateTo(page);
280→  };
281→
282→  const goBack = () => {
283→    setIsMobileMenuOpen(false);
284→    if (viewHistory.length > 0) {
285→      const newHistory = [...viewHistory];
286→      const prevView = newHistory.pop();
287→      setViewHistory(newHistory);
288→      if (prevView) {
289→        setCurrentView(prevView);
290→        setRefreshKey(prev => prev + 1);
291→      }
292→    } else {
293→      setCurrentView('home');
294→      setRefreshKey(prev => prev + 1);
295→    }
296→  };
297→
298→  const handleDirectRecharge = (packId: number) => {
299→    setInitialRechargePackId(packId);
300→    navigateTo('recharge');
301→  };
302→
303→  const handleAnalyze = async (url: string) => {
304→    if (user) {
305→        const limit = PLAN_LIMITS[user.plan] || 1;
306→        let hostname = url;
307→        try { hostname = new URL(url).hostname; } catch(e) {}
308→
309→        const isExistingProject = history.some(h => {
310→            try { return new URL(h.url).hostname === hostname; }
311→            catch(e) { return false; }
312→        });
313→
314→        if (!isExistingProject && monthlyProjectCount >= limit) {
315→            alert(`Limite de nouveaux projets atteinte pour ce mois (${monthlyProjectCount}/${limit}). Passez au plan supérieur pour ajouter plus de projets.`);
316→            setInitialAccountTab('subscription');
317→            navigateTo('account');
318→            return;
319→        }
320→    }
321→
322→    setIsAnalyzing(true);
323→    try {
324→      const result = await analyzeUrl(url);
325→      setAnalysisData(result);
326→
327→      const updatedHistory = db.add(result);
328→      setHistory(updatedHistory);
329→
330→      if (history.length === 0) {
331→        setShowCelebration(true);
332→        setTimeout(() => setShowCelebration(false), 3000);
333→      }
334→
335→      showToast('success', 'Audit terminé avec succès !');
336→
337→      setMegaStatus('generating');
338→      megaGenerate(url).then(cache => {
339→        if (cache) {
340→          const preGenerated = { status: 'completed' as const, generatedAt: new Date().toISOString(), ...cache };
341→          setHistory(prev => {
342→            if (prev.length === 0) return prev;
343→            const updated = { ...prev[0], preGenerated };
344→            db.update(0, updated);
345→            return [updated, ...prev.slice(1)];
346→          });
347→          setAnalysisData(prev => prev ? { ...prev, preGenerated } : prev);
348→          setMegaStatus('completed');
349→        } else {
350→          setMegaStatus('failed');
351→        }
352→      }).catch(() => setMegaStatus('failed'));
353→
354→      setResultsTab('details');
355→      navigateTo('projects');
356→    } catch (error) {
357→      console.error("Analysis failed", error);
358→      alert("Erreur lors de l'analyse. Veuillez réessayer.");
359→    } finally {
360→      setIsAnalyzing(false);
361→    }
362→  };
363→
364→  const handleViewAnalysis = (result: AnalysisResult, tab: any = 'overview') => {
365→    setAnalysisData(result);
366→    setResultsTab(tab);
367→    navigateTo('projects');
368→  };
369→
370→  const handleViewDirectoryEntity = (result: AnalysisResult) => {
371→    setAnalysisData(result);
372→    navigateTo('directory-entity');
373→  };
374→
375→  const handleUpdateAnalysis = (index: number, updatedData: Partial<AnalysisResult>) => {
376→    const updatedHistory = db.update(index, updatedData);
377→    setHistory(updatedHistory);
378→  };
379→
380→  const handleSaveSolution = useCallback((analysisId: string, recommendationId: string, solution: GeneratedSolution) => {
381→    const timestamp = new Date().toISOString();
382→    const solutionWithMeta = { ...solution, timestamp };
383→
384→    setAnalysisData(prev => {
385→        if (!prev || prev.timestamp !== analysisId) return prev;
386→        return {
387→            ...prev,
388→            generatedSolutions: {
389→                ...(prev.generatedSolutions || {}),
390→                [recommendationId]: solutionWithMeta
391→            }
392→        };
393→    });
394→
395→    setHistory(prevHistory => {
396→        const index = prevHistory.findIndex(item => item.timestamp === analysisId);
397→        if (index !== -1) {
398→            const updatedItem = {
399→                ...prevHistory[index],
400→                generatedSolutions: {
401→                    ...(prevHistory[index].generatedSolutions || {}),
402→                    [recommendationId]: solutionWithMeta
403→                }
404→            };
405→            const newHistory = [...prevHistory];
406→            newHistory[index] = updatedItem;
407→            db.update(index, updatedItem);
408→            return newHistory;
409→        }
410→        return prevHistory;
411→    });
412→  }, []);
413→
414→  const handleAddToSmcLibrary = (item: SMCContent) => setSmcLibrary(prev => [item, ...prev]);
415→  const handleAddToTruthLibrary = (item: SMCContent) => setTruthLibrary(prev => [item, ...prev]);
416→  const handleAddToSchemaLibrary = (item: SMCContent) => setSchemaLibrary(prev => [item, ...prev]);
417→  const handleAddToRobotsLibrary = (item: SMCContent) => setRobotsLibrary(prev => [item, ...prev]);
418→
419→  const handleNavigateToPublisher = (data: { topic: string, url: string, brief: string }) => {
420→    setPublisherRequestData(data);
421→    navigateTo('publisher-request');
422→  };
423→
424→  const handleNavigateToDirectory = () => {
425→    navigateTo('directory');
426→  };
427→
428→  const handleDeductCredits = (amount: number): boolean => {
429→    if (!user) {
430→        if(confirm("Vous devez être connecté pour effectuer cette action. Se connecter maintenant ?")) {
431→            navigateTo('login');
432→        }
433→        return false;
434→    }
435→
436→    if (user.credits < amount) {
437→        alert(`Solde GTO Gas insuffisant pour générer cette solution.\n\nIl vous manque ${amount - user.credits} crédits.\n\nRedirection vers la station de recharge...`);
438→        navigateTo('recharge');
439→        return false;
440→    }
441→
442→    setUser(prev => prev ? { ...prev, credits: prev.credits - amount } : null);
443→    return true;
444→  };
445→
446→  const handleRecharge = (amount: number, planLevel: 'free' | 'pro' | 'enterprise') => {
447→    if (!user) return;
448→    setUser({
449→        ...user,
450→        credits: user.credits + amount,
451→        plan: planLevel
452→    });
453→  };
454→
455→  const handleUpgradePlan = (newPlan: 'free' | 'pro' | 'enterprise') => {
456→    if (!user) return;
457→    setUser({ ...user, plan: newPlan });
458→  };
459→
460→  const handleLogin = (loggedInUser: User) => {
461→    setUser(loggedInUser);
462→    setViewHistory(['home']);
463→    setCurrentView('dashboard');
464→    setActiveSection('dashboard');
465→    setRefreshKey(prev => prev + 1);
466→  };
467→
468→  const handleLogout = () => {
469→    setIsMobileMenuOpen(false);
470→    setUser(null);
471→    setCurrentView('home');
472→    setActiveSection('dashboard');
473→    setViewHistory([]);
474→    setRefreshKey(prev => prev + 1);
475→  };
476→
477→  useEffect(() => {
478→    if (!user && isMobileMenuOpen) {
479→      setIsMobileMenuOpen(false);
480→    }
481→  }, [user, isMobileMenuOpen]);
482→
483→  // ── Render page content ──
484→  const renderPage = () => {
485→    switch (currentView) {
486→      case 'home':
487→        return <Home key={`home-${refreshKey}`} onNavigate={(view) => navigateTo(view)} user={user} onDirectRecharge={handleDirectRecharge} />;
488→      case 'login':
489→        return <Login key={`login-${refreshKey}`} onLogin={handleLogin} onBack={goBack} />;
490→      case 'dashboard':
491→        return <Dashboard key={`dashboard-${refreshKey}`} onBack={goBack} history={history} onView={handleViewAnalysis} onNavigate={navigateTo} />;
492→      case 'new-analysis':
493→      case 'analyze':
494→        return <Analyze key={`analyze-${refreshKey}`} onAnalyze={handleAnalyze} isAnalyzing={isAnalyzing} />;
495→      case 'generative-tools':
496→        return <GenerativeTools key={`generative-tools-${refreshKey}`} onNavigate={navigateTo} history={history} megaStatus={megaStatus} />;
497→      case 'results':
498→      case 'audit-aeo':
499→        return analysisData ? <Results key={`results-${refreshKey}`} data={analysisData} onBack={goBack} user={user} onDeductCredits={handleDeductCredits} onSaveSolution={handleSaveSolution} initialTab={resultsTab as any} onNewAnalysis={() => navigateTo('new-analysis')} /> : null;
500→      case 'action-plan':
501→      case 'projects':
502→      case 'rescan':
503→        return <Projects key={`projects-${refreshKey}`} onBack={goBack} onNavigateToAnalysis={() => navigateTo('new-analysis')} user={user} history={history} onViewAnalysis={handleViewAnalysis} projectCount={monthlyProjectCount} maxProjects={user ? PLAN_LIMITS[user.plan] : 1} onNavigateToPlan={() => { setInitialAccountTab('subscription'); navigateTo('account'); }} onDeductCredits={handleDeductCredits} onSaveSolution={handleSaveSolution} onNewAnalysis={() => navigateTo('new-analysis')} onNavigateToRecharge={() => navigateTo('credits')} initialUrl={analysisData?.url} initialTab={resultsTab} />;
504→      case 'history':
505→        return <HistoryView key={`history-${refreshKey}`} onBack={goBack} history={history} onView={handleViewAnalysis} />;
506→      case 'citation-dashboard':
507→      case 'ai-monitoring':
508→        return <AiMonitoring key={`ai-monitoring-${refreshKey}`} onBack={goBack} onNavigate={navigateTo} onDeductCredits={handleDeductCredits} user={user} />;
509→      case 'tracked-queries':
510→      case 'benchmark':
511→      case 'monthly-report':
512→        return <PlaceholderPage title={currentView === 'tracked-queries' ? 'Requêtes cibles' : currentView === 'benchmark' ? 'Benchmark' : 'Rapports mensuels'} />;
513→      case 'multilingual':
514→        return <MultilingualCitations key={`multilingual-${refreshKey}`} onBack={goBack} user={user} onDeductCredits={handleDeductCredits} />;
515→      case 'alerts':
516→      case 'alerts-aeo':
517→        return <AlertsAEO key={`alerts-aeo-${refreshKey}`} onBack={goBack} user={user} onNavigate={(view) => navigateTo(view)} />;
518→      case 'smc-studio':
519→        return <SMCStudio key={`smc-studio-${refreshKey}`} onBack={goBack} user={user} onDeductCredits={handleDeductCredits} library={smcLibrary} onAddToLibrary={handleAddToSmcLibrary} onNavigateToPublisher={handleNavigateToPublisher} onNavigateToDirectory={handleNavigateToDirectory} />;
520→      case 'blog-optimizer':
521→        return <BlogOptimizer key={`blog-optimizer-${refreshKey}`} onBack={goBack} user={user} onDeductCredits={handleDeductCredits} onNavigateToPublisher={handleNavigateToPublisher} />;
522→      case 'schema-org':
