@tailwind base;
@tailwind components;
@tailwind utilities;

/* ═══════════════════════════════════════════════════════════
   DESIGN SYSTEM — CitedBy.ai
   Inspiré de Linear, Vercel, Stripe, Raycast, Notion
   ═══════════════════════════════════════════════════════════ */

:root {
  /* ═══ SURFACES ═══ */
  --bg-base:        #09090B;     /* Fond principal (zinc-950) */
  --bg-surface:     #18181B;     /* Cards, sidebar (zinc-900) */
  --bg-elevated:    #27272A;     /* Inputs, hovers (zinc-800) */
  --bg-overlay:     #3F3F46;     /* Tooltips, dropdowns (zinc-700) */

  /* ═══ BORDERS ═══ */
  --border-default: #27272A;     /* Bordures standards (zinc-800) */
  --border-subtle:  #1E1E22;     /* Bordures légères */
  --border-strong:  #3F3F46;     /* Bordures actives (zinc-700) */

  /* ═══ TEXTE ═══ */
  --text-primary:   #FAFAFA;     /* Titres, texte important (zinc-50) */
  --text-secondary: #A1A1AA;     /* Texte secondaire (zinc-400) */
  --text-tertiary:  #71717A;     /* Labels, hints (zinc-500) */
  --text-disabled:  #52525B;     /* Désactivé (zinc-600) */

  /* ═══ ACCENTS ═══ */
  --accent:         #3B82F6;     /* Bleu primaire (blue-500) */
  --accent-hover:   #2563EB;     /* Bleu hover (blue-600) */
  --accent-subtle:  #3B82F610;   /* Bleu très léger pour backgrounds */
  --accent-text:    #60A5FA;     /* Bleu pour texte sur fond sombre (blue-400) */

  /* ═══ SÉMANTIQUE ═══ */
  --success:        #22C55E;     /* Vert (green-500) */
  --success-subtle: #22C55E15;
  --warning:        #F59E0B;     /* Orange (amber-500) */
  --warning-subtle: #F59E0B15;
  --error:          #EF4444;     /* Rouge (red-500) */
  --error-subtle:   #EF444415;

  /* ═══ MOTEURS IA (identité visuelle) ═══ */
  --engine-chatgpt:    #10B981;  /* Emerald */
  --engine-perplexity: #3B82F6;  /* Blue */
  --engine-gemini:     #8B5CF6;  /* Violet */

  /* ═══ SURFACES GLASSMORPHISM ═══ */
  --glass-bg:         rgba(9, 9, 11, 0.8);
  --glass-bg-strong:  rgba(9, 9, 11, 0.9);
  --glass-border:     rgba(255, 255, 255, 0.06);
  --glass-border-hover: rgba(255, 255, 255, 0.1);
  --glass-surface:    rgba(255, 255, 255, 0.04);
  --glass-surface-hover: rgba(255, 255, 255, 0.06);
  --glass-active:     rgba(255, 255, 255, 0.08);

  color-scheme: dark;
}

/* ═══════════════════════════════════════════════════════════
   FONDATIONS
   ═══════════════════════════════════════════════════════════ */

html, body, #root {
  margin: 0;
  padding: 0;
  min-height: 100%;
  background-color: var(--bg-base);
  color: var(--text-primary);
  font-family: 'Geist Sans', 'Inter', system-ui, -apple-system, sans-serif;
  line-height: 1.45;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  text-rendering: optimizeLegibility;
}

code, pre, .font-mono, kbd {
  font-family: 'Geist Mono', 'SF Mono', Consolas, monospace;
