    { type: 'link', id: 'answer-first',    label: 'Answer First Audit', icon: MessageSquare },
    { type: 'link', id: 'eeat-builder',    label: 'E-E-A-T Builder',    icon: Shield },
    { type: 'link', id: 'reputation',      label: 'Réputation',         icon: AlertTriangle },
  ],

  technique: [
    { type: 'link', id: 'schema-org',       label: 'Schema.org',          icon: Code },
    { type: 'link', id: 'robots-txt',       label: 'Robots.txt',         icon: Bot },
    { type: 'link', id: 'source-of-truth',  label: 'Source of Truth',    icon: FileCheck },
    { type: 'link', id: 'llms-txt',         label: 'LLMs.txt Generator', icon: FileJson },
  ],

  marketplace: [
    { type: 'link', id: 'publisher-search',  label: 'Trouver publishers', icon: Globe },
    { type: 'link', id: 'directory',         label: 'Annuaire',           icon: Compass },
    { type: 'link', id: 'clients',           label: 'Clients',            icon: Users },
    { type: 'link', id: 'messages',          label: 'Messages',           icon: MessageSquare },
    { type: 'link', id: 'mission-orders',    label: 'Commandes',          icon: ShoppingBag },
  ],

  compte: [
    { type: 'link', id: 'account',        label: 'Mon compte',        icon: User },
    { type: 'link', id: 'plan',           label: 'Abonnement',        icon: CreditCard },
    { type: 'link', id: 'recharge',       label: 'Recharger crédits', icon: Coins },
    { type: 'link', id: 'projects',       label: 'Projets',           icon: LayoutGrid },
    { type: 'link', id: 'integrations',   label: 'Intégrations',      icon: Link },
    { type: 'link', id: 'api-developer',  label: 'API Développeur',   icon: Key },
    { type: 'link', id: 'affiliation',    label: 'Affiliation',       icon: Users },
  ],
};

export { SIDEBAR_ITEMS };

// ═══════════════════════════════════════════════════════════
// PAGE ALIASES — pour le highlight du bon item
// ═══════════════════════════════════════════════════════════

const PAGE_ALIASES: Record<string, string> = {
  'analyze': 'new-analysis',
  'audit-aeo': 'results',
  'alerts': 'alerts-aeo',
  'answer-first-audit': 'answer-first',
  'api-keys': 'api-developer',
  'credits': 'recharge',
  'profile': 'account',
  'subscription': 'plan',
  'publisher-request': 'publisher-search',
  'generative-tools': 'smc-studio',
  'directory-entity': 'directory',
};

function resolveActivePage(pageId: string): string {
  return PAGE_ALIASES[pageId] || pageId;
}

// ═══════════════════════════════════════════════════════════
// COMPONENT
// ═══════════════════════════════════════════════════════════

interface SidebarProps {
  section: string;
  activePage: string;
  onPageChange: (page: string) => void;
  onSectionChange: (section: string) => void;
  credits: number;
  plan: string;
  onLogoClick?: () => void;
}

export default function Sidebar({
  section,
  activePage,
  onPageChange,
  onSectionChange,
  credits,
  plan,
  onLogoClick,
}: SidebarProps) {
  const [mobileOpen, setMobileOpen] = useState(false);
  const items = SIDEBAR_ITEMS[section];
  const resolved = resolveActivePage(activePage);

  // ── Render nav items (Raycast style) ──
  const renderNavItems = (entries: SidebarEntry[], onClose?: () => void) => (
    <nav className="flex-1 overflow-y-auto py-3 px-3">
      {entries.map((entry, i) => {
        if (entry.type === 'separator') {
          return (
            <div key={`sep-${i}`} className="text-[11px] font-medium uppercase tracking-wider text-zinc-600 px-3 mt-5 mb-1.5">
              {entry.label}
            </div>
          );
        }

        const Icon = entry.icon;
        const isActive = resolved === entry.id;
        return (
          <button
            key={entry.id}
            onClick={() => { onPageChange(entry.id); onClose?.(); }}
            className={`group flex items-center gap-2.5 w-full px-2.5 py-[7px] rounded-lg text-[13px] leading-none cursor-pointer transition-all duration-150 relative ${
              isActive
                ? 'text-white bg-white/[0.08]'
                : 'text-zinc-500 hover:text-zinc-300 hover:bg-white/[0.04]'
            }`}
          >
            {isActive && (
              <div className="absolute left-0 top-1/2 -translate-y-1/2 w-[2px] h-4 bg-blue-500 rounded-r-full" />
            )}
            <Icon className={`w-4 h-4 flex-shrink-0 ${
              isActive
                ? 'text-blue-400'
                : 'text-zinc-600 group-hover:text-zinc-400'
            }`} />
            <span className="truncate">{entry.label}</span>
            {entry.badge && (
              <span className={`ml-auto text-[10px] font-semibold min-w-[18px] h-[18px] rounded-full flex items-center justify-center px-1 ${
                entry.badgeColor === 'red'
                  ? 'bg-red-500/15 text-red-400'
                  : 'bg-[var(--bg-elevated)] text-[var(--text-tertiary)]'
              }`}>
                {entry.badge}
              </span>
            )}
          </button>
        );
      })}
    </nav>
  );

  // ── Credits footer ──
  const creditsFooter = (
    <div className="border-t border-white/[0.06] p-3 flex-shrink-0 mx-1">
      <div className="text-[11px] text-zinc-600 font-medium uppercase tracking-wider">Plan {plan}</div>
      <div className="h-1 w-full rounded-full bg-white/[0.06] mt-2 overflow-hidden">
        <div
          className="h-full bg-blue-500 rounded-full transition-all duration-500"
          style={{ width: `${Math.min(100, (credits / 200) * 100)}%` }}
        />
      </div>
      <div className="text-[11px] text-zinc-600 mt-1.5">
        <span className="text-zinc-500">{credits}</span> / 200 crédits
      </div>
    </div>
  );

  return (
    <>
      {/* ═══ Desktop sidebar ═══ */}
      {items && items.length > 0 && (
        <aside className="hidden md:flex flex-col shrink-0 w-60 bg-[#09090B]/90 backdrop-blur-md border-r border-white/[0.06] overflow-y-auto">
          {renderNavItems(items)}
          {creditsFooter}
        </aside>
      )}

      {/* ═══ Mobile hamburger button ═══ */}
      <button
        onClick={() => setMobileOpen(!mobileOpen)}
        className="md:hidden fixed top-3 left-3 z-[60] p-2 rounded-lg bg-[var(--bg-elevated)]/80 backdrop-blur text-[var(--text-secondary)] hover:text-[var(--text-primary)]"
      >
        {mobileOpen ? <X size={20} /> : <Menu size={20} />}
      </button>

      {/* ═══ Mobile overlay ═══ */}
      {mobileOpen && (
        <>
          <div
            className="md:hidden fixed inset-0 z-[55] bg-black/60 backdrop-blur-sm"
            onClick={() => setMobileOpen(false)}
          />
          <aside className="md:hidden flex flex-col fixed top-0 left-0 bottom-0 w-72 z-[56] bg-[var(--bg-base)] border-r border-[var(--border-subtle)]">
            {/* Logo */}
            <div
              className="px-5 h-14 flex items-center border-b border-[var(--border-subtle)] flex-shrink-0 cursor-pointer"
              onClick={() => { onLogoClick?.(); setMobileOpen(false); }}
            >
              <span className="text-[var(--text-primary)] font-semibold text-[15px] tracking-tight">Cited</span>
              <span className="text-[var(--accent-text)] font-semibold text-[15px]">By</span>
              <span className="text-[var(--text-tertiary)] font-normal text-[13px]">.ai</span>
            </div>

            {/* Section tabs (mobile) */}
            <div className="px-3 py-3 border-b border-[var(--border-subtle)] flex-shrink-0">
              <div className="flex flex-wrap gap-1">
                {SECTIONS.map(s => (
                  <button
                    key={s.id}
                    onClick={() => {
                      onSectionChange(s.id);
                      if (s.id === 'dashboard') setMobileOpen(false);
                    }}
                    className={`px-2.5 py-1.5 rounded-md text-xs font-medium transition-all ${
                      section === s.id
                        ? 'text-[var(--text-primary)] bg-[var(--bg-surface)]'
                        : 'text-[var(--text-tertiary)] hover:text-[var(--text-secondary)] hover:bg-[var(--bg-surface)]'
                    }`}
                  >
                    {s.label}
                  </button>
                ))}
              </div>
            </div>

            {/* Sub-items for active section */}
            {items && items.length > 0
              ? renderNavItems(items, () => setMobileOpen(false))
              : (
                <div className="flex-1 flex items-center justify-center">
                  <p className="text-sm text-[var(--text-tertiary)]">Dashboard — pleine largeur</p>
                </div>
              )
            }

            {creditsFooter}
          </aside>
        </>
      )}
    </>
  );
}

