import React from 'react';
import { AnalysisResult } from '../types';
import HeroWelcome from '../components/dashboard/HeroWelcome';
import StatsOverview from '../components/dashboard/StatsOverview';
import DualModelExplainer from '../components/dashboard/DualModelExplainer';
import QuickActions from '../components/dashboard/QuickActions';

interface DashboardProps {
  onBack: () => void;
  history: AnalysisResult[];
  onView: (analysis: AnalysisResult) => void;
  onNavigate: (view: any) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ onBack, history, onView, onNavigate }) => {
  // TODO: These will come from Supabase/auth context later
  const userName = 'Utilisateur';
  const planName = 'Pro';
  const credits = 142;
  const maxCredits = 200;

  // Derive stats from history if available
  const lastAuditScore = history.length > 0 ? history[0].globalScore : null;
  const citationCount = history.reduce((sum, h) => sum + (h.aiCitation?.probability > 50 ? 1 : 0), 0);
  const languagesCount = 0;
  const alertsCount = 0;

  return (
    <div className="space-y-10 page-enter">
      {/* SECTION 1 — Hero Welcome */}
      <HeroWelcome
        userName={userName}
        planName={planName}
        credits={credits}
        maxCredits={maxCredits}
        onNavigate={onNavigate}
      />

      {/* SECTION 2 — Stats rapides */}
      <StatsOverview
        stats={{
          aeoScore: lastAuditScore,
          citationCount,
          languagesAnalyzed: languagesCount,
          activeAlerts: alertsCount,
        }}
      />

      {/* SECTION 3 — Double modele economique */}
      <DualModelExplainer
        credits={credits}
        maxCredits={maxCredits}
        planName={planName}
        currentPlan={planName.toLowerCase() as 'free' | 'starter' | 'pro' | 'agence'}
        onNavigate={onNavigate}
      />

      {/* SECTION 4 — Actions rapides */}
      <QuickActions
        credits={credits}
        onNavigate={onNavigate}
      />
    </div>
  );
};

export default Dashboard;
